/**
 * @name XSS Protection API - unsafe output in web console plugin
 * @description Checks if user input flows to response output in the WebConsole plugin without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-webconsole-output
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module XSSWebConsoleConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
    or
    // HttpServletRequest parameter access
    exists(MethodCall mc |
      mc.getMethod().hasName("getParameter") and
      source.asExpr() = mc
    )
    or
    // Request URI / path
    exists(MethodCall mc |
      mc.getMethod().hasName("getRequestURI") and
      source.asExpr() = mc
    )
    or
    // Request path info
    exists(MethodCall mc |
      mc.getMethod().hasName("getPathInfo") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // PrintWriter write/println
    exists(MethodCall mc |
      mc.getMethod().hasName("write") or
      mc.getMethod().hasName("println") or
      mc.getMethod().hasName("print") or
      mc.getMethod().hasName("append") |
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // StringBuilder/StringBuffer append that feeds into output
    exists(MethodCall mc |
      mc.getMethod().hasName("append") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "AbstractStringBuilder") |
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module XSSWebConsoleFlow = TaintTracking::Global<XSSWebConsoleConfig>;
import XSSWebConsoleFlow::PathGraph

from XSSWebConsoleFlow::PathNode source, XSSWebConsoleFlow::PathNode sink
where XSSWebConsoleFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Potential XSS: user input flows to output without encoding from $@.", source.getNode(), "user input"

/**
 * @name WebConsole stored XSS - blocked URLs in HTML table
 * @description Check if blocked URLs from XSSStatusService are written to HTML table rows without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xss-webconsole-stored-urls-html
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking

module StoredUrlXSSConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // Data from XSSStatusService.getInvalidUrls() and related map operations
    exists(MethodCall mc |
      (mc.getMethod().hasName("getInvalidUrls") or
       mc.getMethod().hasName("getKey") or
       mc.getMethod().hasName("getValue")) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (mc.getMethod().hasName("println") or
       mc.getMethod().hasName("write") or
       mc.getMethod().hasName("print") or
       mc.getMethod().hasName("format") or
       mc.getMethod().hasName("add")) and
      sink.asExpr() = mc.getAnArgument()
    )
  }

  predicate isBarrier(DataFlow::Node node) {
    // Encoding calls are barriers
    exists(MethodCall mc |
      (mc.getMethod().hasName("encodeForHTML") or
       mc.getMethod().hasName("encodeForHTMLAttribute") or
       mc.getMethod().hasName("escapeHtml") or
       mc.getMethod().hasName("escapeXml") or
       mc.getMethod().hasName("encodeHTML") or
       mc.getMethod().hasName("forHtml") or
       mc.getMethod().hasName("encode")) and
      node.asExpr() = mc
    )
  }
}

module StoredUrlXSSFlow = TaintTracking::Global<StoredUrlXSSConfig>;
import StoredUrlXSSFlow::PathGraph

from StoredUrlXSSFlow::PathNode source, StoredUrlXSSFlow::PathNode sink
where StoredUrlXSSFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Stored XSS: URL data from $@ flows to output without HTML encoding.", source.getNode(), "blocked URL store"
